SELECT
FROM order_info o LEFT JOIN sys_user su_p ON o.passenger_id = su_p.id LEFT JOIN sys_user su_d ON o.driver_id = su_d.id LEFT JOIN vehicle_info v ON o.vehicle_id = v.id AND v.is_deleted = 0 LEFT JOIN driver_info di ON o.driver_id = di.user_id LEFT JOIN driver_evaluation de ON o.id = de.order_id WHERE 1=1
AND o.passenger_id = #{passengerId}
AND o.driver_id = #{driverId}
AND o.status = #{status}
AND o.status IN
#{s}
ORDER BY o.create_time DESC

